SELECT ?party_type (COUNT(?p) AS ?count)
WHERE {
  ?p a <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Party> ;
     <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Party/party_type> ?party_type .
}
GROUP BY ?party_type
ORDER BY DESC(?count)
LIMIT 5

SELECT DISTINCT ?holding_id WHERE {
  ?lp1 a <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/LifeParticipant> ;
       <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/LifeParticipant/holding_id> ?holding_id ;
       <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/LifeParticipant/party_id> ?party_id ;
       <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/LifeParticipant/participant_sk> ?sk1 ;
       <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/LifeParticipant/is_deleted> ?del1 .

  ?lp2 a <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/LifeParticipant> ;
       <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/LifeParticipant/holding_id> ?holding_id ;
       <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/LifeParticipant/party_id> ?party_id ;
       <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/LifeParticipant/participant_sk> ?sk2 ;
       <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/LifeParticipant/is_deleted> ?del2 .

  FILTER(?sk1 != ?sk2)
  FILTER(LCASE(STR(?del1)) = "false")
  FILTER(LCASE(STR(?del2)) = "false")
}

SELECT DISTINCT ?riderName ?fullName ?coverageType WHERE {
  ?rider a <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Rider> ;
         <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Rider/rider_name> ?riderName ;
         <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Rider/holding_id> ?hid .

  ?coverage a <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Coverage> ;
            <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Coverage/holding_id> ?hid ;
            <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Coverage/coverage_type> ?coverageType ;
            <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Coverage/hasParty> ?party .

  ?party a <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Party> ;
         <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Party/full_name> ?fullName .
}
ORDER BY ?riderName ?fullName

SELECT ?fullName (SUM(xsd:decimal(?cv)) AS ?totalMarketValue)
WHERE {
  ?hs a <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/HoldingSubaccount> ;
      <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/HoldingSubaccount/holding_id> ?holdingId ;
      <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/HoldingSubaccount/currentvalue> ?cv ;
      <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/HoldingSubaccount/deleted> ?del .
  FILTER(LCASE(STR(?del)) = "false")

  ?cov a <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Coverage> ;
       <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Coverage/holding_id> ?holdingId ;
       <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Coverage/coverage_status> ?covStatus ;
       <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Coverage/party_id> ?partyKey .
  FILTER(?covStatus = "Active")

  BIND(CONCAT("PARTY#", ?partyKey) AS ?partyIri)

  ?party a <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Party> ;
         <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Party/party_id> ?partyIri ;
         <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/Party/full_name> ?fullName .
}
GROUP BY ?fullName

SELECT DISTINCT ?product_name
WHERE {
  ?cp a <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/CoverageProduct> ;
      <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/CoverageProduct/product_name> ?product_name .
}
ORDER BY ?product_name
LIMIT 10

SELECT ?month (SUM(xsd:decimal(?amt)) AS ?totalAmount) WHERE {
  ?fa a <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/FinancialActivity> ;
      <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/FinancialActivity/transaction_date> ?d ;
      <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/FinancialActivity/transaction_amount> ?amt ;
      <http://curated-layer-ontology-20260701-040122/ontology/vkg-ontology_curated_layer-3d1fde76/FinancialActivity/is_deleted> ?del .
  FILTER(LCASE(STR(?del)) = "false")
  FILTER(SUBSTR(STR(?d),1,4) = "2024")
  BIND(SUBSTR(STR(?d),1,7) AS ?month)
}
GROUP BY ?month
ORDER BY ?month
